def is_palindrome(s):
    cleaned = "".join(ch.lower() for ch in s if ch.isalnum())
    return cleaned == cleaned[::-1]

if __name__ == "__main__":
    for text in ["racecar", "A man a plan a canal Panama", "hello"]:
        print(f"{text!r}: {is_palindrome(text)}")
