def is_prime(n):
    if n < 2:
        return False
    for d in range(2, int(n ** 0.5) + 1):
        if n % d == 0:
            return False
    return True

if __name__ == "__main__":
    primes = [n for n in range(50) if is_prime(n)]
    print(primes)
