def caesar(text, shift):
    result = []
    for ch in text:
        if ch.isalpha():
            base = ord("A") if ch.isupper() else ord("a")
            result.append(chr((ord(ch) - base + shift) % 26 + base))
        else:
            result.append(ch)
    return "".join(result)

if __name__ == "__main__":
    message = "Hello, World!"
    encoded = caesar(message, 3)
    print("Encoded:", encoded)
    print("Decoded:", caesar(encoded, -3))
```

