class Stack:
    def __init__(self):
        self._items = []

    def push(self, item):
        self._items.append(item)

    def pop(self):
        if not self._items:
            raise IndexError("pop from empty stack")
        return self._items.pop()

    def peek(self):
        return self._items[-1] if self._items else None

    def is_empty(self):
        return not self._items

if __name__ == "__main__":
    s = Stack()
    for x in (1, 2, 3):
        s.push(x)
    print("Top:", s.peek())
    print("Popped:", s.pop())
    print("Empty?", s.is_empty())
```

